const err     = $input.first().json;
const wfName  = err.workflow?.name || 'Unknown Workflow';
const errMsg  = err.execution?.error?.message || 'No error message';
const errNode = err.execution?.error?.node?.name || 'Unknown Node';
const execId  = err.execution?.id || 'N/A';
const execUrl = `${$env.N8N_BASE_URL}/workflow/${err.workflow?.id}/executions/${execId}`;
const ts      = new Date().toISOString();

const slackText = [
  ':rotating_light: *n8n Workflow Error*',
  '',
  `*Workflow:*  ${wfName}`,
  `*Node:*      ${errNode}`,
  `*Error:*     ${errMsg}`,
  `*Exec ID:*   ${execId}`,
  `*Time:*      ${ts}`,
  '',
  `<${execUrl}|View Execution>`,
].join('\n');

const whatsappText = [
  '🚨 n8n Error Alert',
  `Workflow: ${wfName}`,
  `Node: ${errNode}`,
  `Error: ${errMsg.slice(0, 200)}`,
  `Time: ${ts}`,
].join('\n');

return [{ json: { wfName, errMsg, errNode, execId, execUrl, ts, slackText, whatsappText } }];
